import React from "react";

const Header = () => {
  return (
    <header className="d-flex flex-row align-items-center gap-2 bg-light">
      <img src={logo} alt="logo" style={{ width: "20px" }} className="ms-2" />
      <h5 className="my-1 p-1 fw-bold text-primary">
        משפט נט - ניהול משרד עורך דין
      </h5>
    </header>
  );
};

export default Header;
